          <p className="text-slate-500 mt-2 font-medium">
            Manage your profile information and account security.
          </p>
        </div>

        <div className="max-w-4xl grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Profile Card */}
          <div className="lg:col-span-1 space-y-6">
            <div className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm text-center">
              <div className="w-24 h-24 rounded-full bg-indigo-50 border-4 border-white shadow-lg mx-auto flex items-center justify-center text-3xl font-bold text-indigo-600 mb-4">
                {name.charAt(0)}
              </div>
              <h3 className="font-bold text-slate-900 text-lg">{name}</h3>
              <p className="text-sm text-slate-500 capitalize mb-6">{role}</p>
              <button className="text-xs font-bold text-indigo-600 hover:text-indigo-700 transition-colors">
                Change Profile Photo
              </button>
            </div>

            <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm">
                <h4 className="font-bold text-slate-800 text-sm mb-4">Security Status</h4>
                <div className="space-y-4">
                    <div className="flex items-center justify-between text-xs">
                        <span className="text-slate-500">Two-Factor Auth</span>
                        <span className="px-2 py-1 bg-rose-50 text-rose-600 rounded-md font-bold">Disabled</span>
                    </div>
                    <div className="flex items-center justify-between text-xs">
                        <span className="text-slate-500">Last Login</span>
                        <span className="text-slate-900 font-bold">2 hours ago</span>
                    </div>
                </div>
            </div>
          </div>

          {/* Form Area */}
          <div className="lg:col-span-2 space-y-8">
            <div className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm">
               <h3 className="text-lg font-bold text-slate-900 mb-8 border-b border-slate-50 pb-4 flex items-center">
                 <User className="mr-3 text-indigo-500" size={20} />
                 Personal Information
               </h3>

               <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                 <div className="space-y-2">
                   <label className="text-sm font-bold text-slate-700">Display Name</label>
                   <div className="relative">
                     <User className="absolute left-3 top-3 text-slate-300" size={18} />
                     <input 
                       type="text"
                       value={name}
                       onChange={(e) => setName(e.target.value)}
                       className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-2xl focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm font-medium text-slate-900" 
                     />
                   </div>
                 </div>

                 <div className="space-y-2">
                   <label className="text-sm font-bold text-slate-700">Email Address</label>
                   <div className="relative">
                     <Mail className="absolute left-3 top-3 text-slate-300" size={18} />
                     <input 
                       type="email"
                       value={email}
                       readOnly
                       className="w-full pl-10 pr-4 py-3 bg-slate-100 border border-slate-200 rounded-2xl cursor-not-allowed opacity-60 text-sm font-medium text-slate-500" 
                     />
                   </div>
                 </div>

                 <div className="space-y-2">
                   <label className="text-sm font-bold text-slate-700">Current Role</label>
                   <div className="relative">
                     <Shield className="absolute left-3 top-3 text-slate-300" size={18} />
                     <input 
                       type="text"
                       value={role}
                       readOnly
                       className="w-full pl-10 pr-4 py-3 bg-slate-100 border border-slate-200 rounded-2xl cursor-not-allowed opacity-60 text-sm font-medium text-slate-500 capitalize" 
                     />
                   </div>
                 </div>

                 <div className="space-y-2">
                   <label className="text-sm font-bold text-slate-700">Notifications</label>
                   <div className="relative">
                     <Bell className="absolute left-3 top-3 text-slate-300" size={18} />
                     <select className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-2xl focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm font-medium text-slate-900 appearance-none">
                       <option>All Notifications</option>
                       <option>Important Only</option>
                       <option>Muted</option>
                     </select>
                   </div>
                 </div>
               </div>

               <div className="mt-10 flex justify-end">
                 <button 
                   onClick={handleSave}
                   disabled={saving}
                   className="px-8 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl text-sm font-bold shadow-lg shadow-indigo-200 transition-all flex items-center disabled:opacity-50"
                 >
                   {saving ? <Loader2 className="animate-spin mr-2" size={18} /> : <Save className="mr-2" size={18} />}
                   {saving ? "Saving..." : "Save Changes"}
                 </button>
               </div>
            </div>
          </div>
        </div>
      </div>
    </MainLayout>
  );
}

"use client";

import { useQuery } from "@apollo/client/react";
import { GET_DEPT_DASHBOARD_STATS, DashboardStats } from "@/lib/graphql";
import { 
  Users, 
  MessageSquare,
  Building2,
  TrendingUp,
  Loader2,
  BarChart3
} from "lucide-react";

export function DeptDashboardView({ departmentId }: { departmentId: string }) {
  const { data, loading, error } = useQuery<DashboardStats>(GET_DEPT_DASHBOARD_STATS, {
    variables: { departmentId },
    skip: !departmentId
  });

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[400px]">
        <Loader2 className="animate-spin text-indigo-600" size={48} />
      </div>
    );
  }

  if (error) {
    return (
      <div className="p-8 bg-rose-50 border border-rose-100 rounded-3xl text-rose-600">
        <h2 className="text-lg font-bold">Error loading department dashboard</h2>
        <p className="mt-2 text-sm">{error.message}</p>
      </div>
    );
  }

  const stats = [
    { label: "My Interns", value: data?.interns_aggregate?.aggregate?.count || "0", icon: Users, color: "bg-indigo-500" },
    { label: "Dept Feedback", value: data?.feedback_aggregate?.aggregate?.count || "0", icon: MessageSquare, color: "bg-violet-500" },
    { label: "Department", value: "Active", icon: Building2, color: "bg-emerald-500" },
  ];

  return (
    <div className="space-y-6 lg:space-y-8 animate-in fade-in duration-500">
      {/* Header */}
      <div className="px-4 lg:px-0">
        <h1 className="text-2xl lg:text-3xl font-bold text-slate-900 tracking-tight">
          Department <span className="text-indigo-600">Dashboard</span>
        </h1>
        <p className="text-slate-500 mt-1 lg:mt-2 font-medium text-sm lg:text-base">
          Management overview for your department's interns.
        </p>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 lg:gap-6 px-4 lg:px-0">
        {stats.map((stat) => {
          const Icon = stat.icon;
          return (
            <div 
              key={stat.label}
              className="bg-white p-5 lg:p-6 rounded-3xl border border-slate-100 shadow-sm shadow-slate-200/40 hover:shadow-md transition-shadow"
            >
              <div className="flex items-center justify-between">
                <div className={`p-2.5 lg:p-3 rounded-2xl ${stat.color} text-white`}>
                  <Icon size={20} className="lg:w-6 lg:h-6" />
                </div>
                <span className="text-[10px] lg:text-xs font-bold text-emerald-600 bg-emerald-50 px-2 py-1 rounded-full flex items-center">
                  <TrendingUp size={12} className="mr-1" />
                  Live
                </span>
              </div>
              <div className="mt-4">
                <h3 className="text-slate-500 text-xs lg:text-sm font-medium">{stat.label}</h3>
                <p className="text-xl lg:text-2xl font-bold text-slate-900 mt-1">{stat.value}</p>
              </div>
            </div>
          );
        })}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 lg:gap-8 px-4 lg:px-0">
        <div className="lg:col-span-2 bg-white p-5 lg:p-8 rounded-3xl border border-slate-100 shadow-sm">
           <h3 className="text-base lg:text-lg font-bold text-slate-900 mb-6 uppercase tracking-tight">Department Interns</h3>
           <div className="overflow-x-auto rounded-2xl border border-slate-100 scrollbar-hide">
             <table className="w-full text-left border-collapse min-w-[500px]">
               <thead>
                 <tr className="bg-slate-50/50">
                    <th className="px-6 py-3 text-[10px] font-black text-slate-400 uppercase tracking-widest">Name</th>
                    <th className="px-6 py-3 text-[10px] font-black text-slate-400 uppercase tracking-widest">College</th>
                 </tr>
               </thead>
               <tbody className="divide-y divide-slate-100">
                 {data?.recent_interns?.length ? data.recent_interns.map(intern => (
                   <tr key={intern.id} className="hover:bg-slate-50 transition-colors">
                     <td className="px-6 py-4 text-sm font-bold text-slate-700">{intern.user.name}</td>
                     <td className="px-6 py-4 text-sm text-slate-500">{intern.college_name}</td>
                   </tr>
                 )) : (
                   <tr><td colSpan={2} className="px-6 py-8 text-center text-slate-400 italic">No interns in this department yet</td></tr>
                 )}
               </tbody>
             </table>
           </div>
        </div>

        <div className="bg-white p-5 lg:p-8 rounded-3xl border border-slate-100 shadow-sm">
           <h3 className="text-base lg:text-lg font-bold text-slate-900 mb-6 uppercase tracking-tight">Recent Reports</h3>
